document.addEventListener("DOMContentLoaded", function () {

    var _url = "/_api/cloudflow/v1.0/trigger/b5966fbe-3028-f111-8341-000d3a36c81b";

    // Empty payload (since no input required)
    var payload = {
        eventData: JSON.stringify({})
    };

    console.log("Triggering flow on page load...");

    shell.ajaxSafePost({
        type: "POST",
        url: _url,
        data: payload
    })
    .done(function (response) {
        try {
            const result = JSON.parse(response);
            console.log("Flow Output:", result);
        } catch (e) {
            console.log("Raw Response:", response);
        }
    })
    .fail(function (error) {
        console.error("Flow trigger failed:", error);
    });

});"}
